DFS+记忆化搜索。从(1,1)到(m,m)，无色格子可用魔法变颜色花费3，同色走花费0，异色走花费1。魔法用后需等2步。

```cpp
#include <bits/stdc++.h>
using namespace std;
int m,n,cor[105][105],f[105][105][2];
int dx[]={-1,1,0,0},dy[]={0,0,-1,1};

void dfs(int x,int y,int used) {
    for(int d=0;d<4;d++) {
        int nx=x+dx[d],ny=y+dy[d];
        if(nx<1||nx>m||ny<1||ny>m) continue;
        if(cor[nx][ny]) {
            int w=(cor[nx][ny]!=cor[x][y]);
            if(f[x][y][used]+w<f[nx][ny][0]) {
                f[nx][ny][0]=f[x][y][used]+w;
                dfs(nx,ny,0);
            }
        } else if(!used) {
            for(int c=1;c<=2;c++) {
                int w=2+(c!=cor[x][y]);
                if(f[x][y][0]+w<f[nx][ny][1]) {
                    f[nx][ny][1]=f[x][y][0]+w;
                    cor[nx][ny]=c;
                    dfs(nx,ny,1);
                    cor[nx][ny]=0;
                }
            }
        }
    }
}

int main() {
    cin>>m>>n;
    memset(f,0x3f,sizeof(f));
    for(int i=0;i<n;i++) {
        int x,y,c;cin>>x>>y>>c;
        cor[x][y]=c+1;
    }
    f[1][1][0]=0;
    dfs(1,1,0);
    int ans=min(f[m][m][0],f[m][m][1]);
    cout<<(ans<0x3f3f3f3f?ans:-1)<<endl;
    return 0;
}
```

前缀异或。用map记录每种前缀异或值最后一次出现位置。贪心策略：当pre⊕k出现过时，切分区间并重置。

```cpp
#include <bits/stdc++.h>
using namespace std;
int n,k,ans,pre,arr[500005];
map<int,int> mp;

int main() {
    cin>>n>>k;
    for(int i=1;i<=n;i++) cin>>arr[i];
    mp[0]=0; pre=0; ans=0;
    int last=-1;
    for(int i=1;i<=n;i++) {
        pre^=arr[i];
        int aim=pre^k;
        if(mp.count(aim)&&mp[aim]>=last) {
            ans++;
            last=i-1;
        }
        mp[pre]=i;
    }
    cout<<ans<<endl;
    return 0;
}
```
